module top_module(obf_in,ld,clk,rst,q);input ld,clk,rst;
  input [3:0] obf_in;
  output q;
  reg [3:0]qq;
  assign q=qq[0];
  always @ (posedge clk, posedge rst)
    begin
      if(rst)
         qq<=0; 
      else if(ld)
          qq <=obf_in;
      else
        qq <= {1'b0,qq[3:1]};
    end
endmodule
